export const IntelligenceDigest: React.FC = () => {
  const [items, setItems] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [analyzingId, setAnalyzingId] = useState<string | null>(null);
  const [analysisResult, setAnalysisResult] = useState<{item: NewsItem, result: string} | null>(null);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await fetchDigest(3);
      setItems(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleSatiTriaje = async (item: NewsItem) => {
    setAnalyzingId(item.link);
    try {
      const result = await analyzeUrlWithSATI(item);
      setAnalysisResult({ item, result });
    } catch (err) {
      alert("Error en el análisis de IA");
    } finally {
      setAnalyzingId(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
            <BrainCircuit className="w-7 h-7 text-amber-500" />
            Intelligence Triaje (SATI)
          </h2>
          <p className="text-sm text-gray-500">Analiza fuentes globales y genera reportes automáticos</p>
        </div>
        <button 
          onClick={loadData}
          disabled={loading}
          className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-medium hover:bg-gray-50 transition-all shadow-sm"
        >
          {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
          Actualizar Feed
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-xl border border-gray-100">
           <Loader2 className="w-12 h-12 text-amber-500 animate-spin mb-4" />
           <p className="text-gray-500 font-medium">Sincronizando fuentes de inteligencia...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {items.map((item, idx) => (
            <div key={idx} className="bg-white rounded-xl border border-gray-200 overflow-hidden hover:shadow-lg transition-all flex flex-col group">
              <div className="p-5 flex-1">
                <div className="flex justify-between items-start mb-3">
                  <span className="px-2 py-0.5 bg-amber-50 text-amber-700 text-[10px] font-bold uppercase rounded border border-amber-100">
                    {item.feedTitle}
                  </span>
                  <Calendar className="w-4 h-4 text-gray-300" />
                </div>
                <h3 className="font-bold text-gray-900 leading-snug mb-2 line-clamp-2 group-hover:text-amber-600 transition-colors">
                  {item.title}
                </h3>
                <p className="text-xs text-gray-500 line-clamp-3 mb-4 leading-relaxed">
                  {item.description?.replace(/<[^>]*>?/gm, '') || 'Sin descripción disponible.'}
                </p>
              </div>
              <div className="px-5 py-3 bg-gray-50 border-t border-gray-100 flex items-center justify-between">
                <a 
                  href={item.link} 
                  target="_blank" 
                  rel="noreferrer"
                  className="text-gray-400 hover:text-amber-600 transition-colors"
                >
                  <ExternalLink className="w-4 h-4" />
                </a>
                <button 
                  onClick={() => handleSatiTriaje(item)}
                  disabled={analyzingId === item.link}
                  className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 text-white text-xs font-bold rounded-lg hover:bg-slate-900 transition-all shadow-sm disabled:opacity-50"
                >
                  {analyzingId === item.link ? (
                    <Loader2 className="w-3.5 h-3.5 animate-spin" />
                  ) : (
                    <Zap className="w-3.5 h-3.5 fill-current" />
                  )}
                  Triaje SATI
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Modal de Análisis SATI */}
      {analysisResult && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col animate-in fade-in zoom-in duration-200">
            <div className="flex justify-between items-center p-6 border-b border-gray-100">
              <div className="flex items-center gap-3">
                <div className="bg-amber-500 p-2 rounded-lg">
                  <ClipboardCheck className="w-6 h-6 text-white" />
                </div>
                <div>
                  <h3 className="text-xl font-bold text-gray-900">Resultado de Triaje SATI</h3>
                  <p className="text-sm text-gray-500">{analysisResult.item.title.substring(0, 60)}...</p>
                </div>
              </div>
              <button onClick={() => setAnalysisResult(null)} className="text-gray-400 hover:text-gray-600 p-2 hover:bg-gray-100 rounded-full transition-all">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="p-6 overflow-y-auto flex-1 bg-slate-50">
              <div 
                className="prose prose-slate max-w-none bg-white p-8 rounded-xl border border-gray-200 shadow-sm"
                dangerouslySetInnerHTML={{ __html: parse(analysisResult.result) as string }}
              />
            </div>

            <div className="p-6 border-t border-gray-100 bg-white flex justify-between items-center">
              <div className="text-xs text-gray-400 italic">
                SATI Engine v1.0 • Análisis mediante Gemini AI
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={() => setAnalysisResult(null)}
                  className="px-6 py-2.5 text-gray-600 font-medium hover:bg-gray-100 rounded-xl transition-all"
                >
                  Descartar
                </button>
                <button 
                  onClick={() => {
                    // Aquí iría la lógica para enviar a la base de datos según el tipo detectado
                    alert("Funcionalidad para guardar directamente en base de datos habilitada en próxima versión.");
                    setAnalysisResult(null);
                  }}
                  className="px-8 py-2.5 bg-amber-600 text-white font-bold rounded-xl hover:bg-amber-700 shadow-lg shadow-amber-200 transition-all flex items-center gap-2"
                >
                  Confirmar y Guardar <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

