export const analyzeWithSATI = async (item: NewsItem, customContent?: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contentToAnalyze = customContent || item.description || "";

  const systemPrompt = `Actúa como un experto en Ciberinteligencia (SATI - Sistema Automatizado de Triaje de Inteligencia).
  Analiza la siguiente información de seguridad y genera un reporte estructurado.

  DATOS DISPONIBLES:
  - TÍTULO: ${item.title}
  - CONTENIDO/CONTEXTO: ${contentToAnalyze}
  - REFERENCIA: ${item.link}

  TU TAREA:
  1. Identifica el TIPO de amenaza: Incidente, Exploit, Zero-Day o CVE.
  2. Determina la SEVERIDAD (Baja, Media, Alta, Crítica).
  3. Genera un Formulario SATI en formato Markdown que incluya:
     - Resumen Ejecutivo.
     - Actores de Amenaza involucrados (si se mencionan).
     - Mitigación recomendada.
     - Clasificación técnica.

  Sé extremadamente profesional y utiliza un tono de experto en inteligencia.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: systemPrompt
  });

  return response.text || "No se pudo generar el análisis SATI.";
};

