  const tickets = await fetchTickets();
  const ticket = tickets.find(t => t.id === ticketId);
  if (ticket) {
    const updatedTicket = {
      ...ticket,
      lastUpdated: Date.now(),
      activity: [...ticket.activity, { type: 'comment' as const, timestamp: Date.now(), text }]
    };
    await updateResource('riesgos', String(ticketId), updatedTicket);
  }
};

export const askAI = async (query: string): Promise<{ response: string }> => {
  const res = await fetch(`${API_BASE_URL}/ai/analyze`, {
    method: 'POST',
    headers: getAuthHeaders(),
    body: JSON.stringify({ query })
  });
  const result = await handleResponse(res);
  if (result.success) return result.data;
  throw new Error(result.message);
};

// SATI Triaje Intelligence with Gemini - Optimized for Text Analysis
export const analyzeWithSATI = async (title: string, content: string, sourceLink: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Actúa como un experto en Ciberinteligencia (CTI) y Sistema Automatizado de Triaje de Inteligencia (SATI).
  Tu tarea es analizar el siguiente texto de una noticia de seguridad y generar una ficha estructurada.

  NOTICIA A ANALIZAR:
  Título: ${title}
  Contenido: ${content}
  Fuente original: ${sourceLink}

  ESTRUCTURA DE RESPUESTA (Markdown):
  1. Clasificación: [Incidente / Exploit / Zero-Day / CVE]
  2. Severidad: [Baja / Media / Alta / Crítica]
  3. Resumen Ejecutivo (Max 3 líneas).
  4. Actores de Amenaza Identificados.
  5. Mitigaciones Sugeridas.
  6. Tabla técnica con campos clave extraídos.

  Genera la respuesta en español, de forma técnica y precisa.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });

  return response.text || "No se pudo generar el análisis SATI.";
};

