protectedApiRouter.post('/ai/analyze', async (req, res) => {
    try {
        const { query } = req.body;
        if (!query) return res.status(400).json({ message: "Query is required" });

        const [incidents, risks, alerts, zeroDays] = await Promise.all([
            Incidente.find().sort({ fecha: -1 }).limit(10),
            Risk.find().sort({ lastUpdated: -1 }).limit(10),
            Alerta.find({ criticidad: { $in: ['Alta', 'Critica'] } }).sort({ fecha: -1 }).limit(10),
            ZeroDay.find().sort({ fecha: -1 }).limit(5)
        ]);

        const context = {
            recentIncidents: incidents,
            activeRisks: risks,
            criticalAlerts: alerts,
            recentZeroDays: zeroDays
        };

        const prompt = `
            You are an expert Cyber Threat Intelligence (CTI) Analyst.
            You have access to the following current data from the organization's database:
            ${JSON.stringify(context, null, 2)}

            User Question: "${query}"

            Based on the data provided above, answer the user's question. 
            If the data suggests critical threats, highlight them.
            Provide the answer in a clear, professional, and actionable format.
        `;

        // Retry logic for 503 Overloaded
        let response;
        let lastError;
        const RETRY_LIMIT = 3;

        for(let attempt = 1; attempt <= RETRY_LIMIT; attempt++) {
            try {
                /* Selecting gemini-3-flash-preview for the analysis task */
                response = await ai.models.generateContent({
                    model: 'gemini-3-flash-preview',
                    contents: prompt
                });
                break; // If successful, break the loop
            } catch (err) {
                lastError = err;
                const status = err.status || (err.error && err.error.code);
                // 503: Service Unavailable (Overloaded)
                // 429: Too Many Requests
                if (status === 503 || status === 429) {
                     if (attempt === RETRY_LIMIT) break;
                     const delay = 2000 * attempt; // 2s, 4s...
                     console.warn(`⚠️ Modelo saturado (${status}). Reintentando en ${delay/1000}s...`);
                     await new Promise(resolve => setTimeout(resolve, delay));
                } else {
                    throw err; // Non-retriable error
                }
            }
        }

        if (!response) throw lastError;

        /* Directly access text property for final response */
        res.json({ response: response.text });
    } catch (error) {
        console.error("AI Error:", error);

        const status = error.status || 500;
        const msg = error.message || "Error processing AI request";

        // Handle specific 503 message for the frontend
        if (status === 503) {
             res.status(503).json({ message: "El modelo de IA está saturado momentáneamente. Por favor intenta de nuevo en unos segundos.", error: msg });
        } else {
             res.status(status).json({ message: "Error al procesar la solicitud de IA", error: msg });
        }
    }
});

protectedApiRouter.get('/cve-details/:cveId', async (req, res) => {
    const { cveId } = req.params;
    const nvdUrl = `https://services.nvd.nist.gov/rest/json/cves/2.0?cveId=${cveId}`;
    const circlUrl = `https://cve.circl.lu/api/cve/${cveId}`;

    try {
        const nvdResponse = await axios.get(nvdUrl);
        if (nvdResponse.data && nvdResponse.data.vulnerabilities && nvdResponse.data.vulnerabilities.length > 0) {
            const vulnerability = nvdResponse.data.vulnerabilities[0].cve;
            let cvssScore = 0;
            let severity = 'N/A';

            if (vulnerability.metrics.cvssMetricV31) {
                cvssScore = vulnerability.metrics.cvssMetricV31[0].cvssData.baseScore;
                severity = vulnerability.metrics.cvssMetricV31[0].cvssData.baseSeverity;
            } else if (vulnerability.metrics.cvssMetricV30) {
                cvssScore = vulnerability.metrics.cvssMetricV30[0].cvssData.baseScore;
                severity = vulnerability.metrics.cvssMetricV30[0].cvssData.baseSeverity;
            }

            return res.status(200).json({
                cveId: vulnerability.id,
                cvss: cvssScore,
                severity: severity,
                description: (vulnerability.descriptions.find(d => d.lang === 'en') || {}).value || 'No description.'
            });
        }
        throw new Error("CVE not found in NVD, trying fallback.");

    } catch (nvdError) {
        try {
            const circlResponse = await axios.get(circlUrl);
            if (!circlResponse.data || Object.keys(circlResponse.data).length === 0) {
                return res.status(404).json({ message: `CVE ID ${cveId} no se encontró en ninguna fuente.` });
            }
            const cveData = circlResponse.data;
            const cvssScore = cveData.cvss || 0;
            let severity = 'N/A';
            if (cvssScore >= 9.0) severity = 'CRITICAL';
            else if (cvssScore >= 7.0) severity = 'HIGH';
            else if (cvssScore >= 4.0) severity = 'MEDIUM';
            else if (cvssScore > 0) severity = 'LOW';

            return res.status(200).json({
                cveId: cveData.id,
                cvss: cvssScore,
                severity: severity,
                description: cveData.summary || 'No description available.'
            });

        } catch (circlError) {
            return res.status(500).json({ message: 'Ambas APIs (NVD y CIRCL) fallaron al obtener los datos del CVE.' });
        }
    }
});

