const authenticateToken = (req, res, next) => {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];
    if (token == null) return res.status(401).json({ message: 'Token required.' });
    jwt.verify(token, JWT_SECRET, (err, user) => {
        if (err) return res.status(403).json({ message: 'Invalid token.' });
        req.user = user;
        next();
    });
};

protectedApiRouter.use(authenticateToken);

const createCrudRoutesFor = (modelName, model) => {
    const router = express.Router();
    router.get('/', async (req, res) => { try { const sortKey = model.schema.path('fecha') ? { fecha: -1 } : { createdAt: -1 }; const items = await model.find().sort(sortKey); res.status(200).json(items); } catch (err) { res.status(500).json({ message: `Error ${modelName}`, error: err.message }); } });
    router.post('/', async (req, res) => { try { const newItem = new model(req.body); const savedItem = await newItem.save(); res.status(201).json(savedItem); } catch (err) { res.status(400).json({ message: `Error create ${modelName}`, error: err.message }); } });
    router.put('/:id', async (req, res) => { try { const updatedItem = await model.findByIdAndUpdate(req.params.id, req.body, { new: true }); res.status(200).json(updatedItem); } catch (err) { res.status(400).json({ message: `Error update ${modelName}`, error: err.message }); } });
    router.delete('/:id', async (req, res) => { try { await model.findByIdAndDelete(req.params.id); res.status(204).send(); } catch (err) { res.status(500).json({ message: `Error delete ${modelName}`, error: err.message }); } });
    return router;
};

apiRouter.post('/auth/register', async (req, res) => {
    try {
        const { username, password } = req.body;
        const passwordHash = await bcrypt.hash(password, 10);
        const newUser = new User({ username, passwordHash });
        await newUser.save();
        res.status(201).json({ message: 'User registered.' });
    } catch (err) { res.status(500).json({ message: 'Error registration.' }); }
});

apiRouter.post('/auth/login', async (req, res) => {
    try {
        const { username, password } = req.body;
        const user = await User.findOne({ username });
        if (!user || !await bcrypt.compare(password, user.passwordHash)) return res.status(401).json({ message: 'Invalid credentials.' });
        const token = jwt.sign({ userId: user._id, username: user.username }, JWT_SECRET, { expiresIn: JWT_EXPIRATION_TIME });
        res.status(200).json({ token, username: user.username });
    } catch (err) { res.status(500).json({ message: 'Error login.' }); }
});

apiRouter.post('/fetch-url', async (req, res) => {
    try {
        const { url } = req.body;
        const response = await axios.get(url, { timeout: 10000 });
        res.json({ content: response.data });
    } catch (err) { res.status(500).json({ message: 'Error fetching URL', error: err.message }); }
});

apiRouter.use('/rss-feeds', createCrudRoutesFor('rss-feeds', RssFeed));
apiRouter.get('/digest', async (req, res) => {
    try {
        const days = parseInt(req.query.days, 10) || 7;
        const endDate = new Date();
        const startDate = new Date(); startDate.setDate(endDate.getDate() - days);
