const API_BASE_URL = '/api';

let authToken: string | null = localStorage.getItem('authToken');

export const setAuthToken = (token: string | null) => {
  authToken = token;
  if (token) {
    localStorage.setItem('authToken', token);
  } else {
    localStorage.removeItem('authToken');
  }
};

const getAuthHeaders = (): HeadersInit => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  if (authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }
  return headers;
};

const handleResponse = async (response: Response): Promise<ApiResponse> => {
  try {
    const contentType = response.headers.get('content-type');
    const isJson = contentType && contentType.includes('application/json');

    if (response.status === 401 || response.status === 403) {
      setAuthToken(null);
    }

    if (isJson) {
      const data = await response.json();
      if (response.ok) {
        return { success: true, data: data.data || data, message: data.message };
      } else {
        return { success: false, message: data.message || `Error ${response.status}` };
      }
    } else {
      if (response.ok) return { success: true, data: null };
      const text = await response.text();
      return { success: false, message: `Error ${response.status}: ${text.substring(0, 100)}` };
    }
  } catch (error: any) {
    return { success: false, message: error.message || 'Error al procesar respuesta' };
  }
};

export const fetchResource = async <T>(endpoint: string): Promise<T[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}`, { headers: getAuthHeaders() });
    const result = await handleResponse(response);
    return result.success ? result.data : [];
  } catch { return []; }
};

export const createResource = async <T>(endpoint: string, data: T): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}`, {
      method: 'POST',
      headers: getAuthHeaders(),
      body: JSON.stringify(data)
    });
    return handleResponse(response);
  } catch (error: any) {
    return { success: false, message: error.message };
  }
};

export const updateResource = async <T>(endpoint: string, id: string, data: T): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}/${id}`, {
      method: 'PUT',
      headers: getAuthHeaders(),
      body: JSON.stringify(data)
    });
    return handleResponse(response);
  } catch (error: any) {
    return { success: false, message: error.message };
  }
};

export const deleteResource = async (endpoint: string, id: string): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}/${id}`, {
      method: 'DELETE',
      headers: getAuthHeaders()
    });
    return response.status === 204 ? { success: true } : handleResponse(response);
  } catch (error: any) {
    return { success: false, message: error.message };
  }
};

export const fetchUrlContent = async (url: string): Promise<string> => {
  const response = await fetch(`${API_BASE_URL}/fetch-url`, {
    method: 'POST',
    headers: getAuthHeaders(),
    body: JSON.stringify({ url })
  });
  const result = await handleResponse(response);
  if (result.success) return result.data.content;
  throw new Error(result.message);
};

export const analyzeWithSATIJSON = async (content: string, url: string): Promise<{type: string, data: any}> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY no detectada. Asegúrate de iniciar la app con la variable de entorno configurada (ej: set API_KEY=tu_clave).");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `Actúa como un experto Analista de CTI (Cyber Threat Intelligence).
  Analiza el siguiente contenido extraído de una URL y clasifícalo en uno de estos módulos: 'incidentes', 'exploits', 'zerodays' o 'cves'.

  CONTENIDO A ANALIZAR:
  ${content.substring(0, 15000)}

  URL ORIGINAL: ${url}

  REGLAS DE SALIDA:
  Debes devolver un objeto JSON con dos propiedades:
  1. 'type': El nombre del módulo (endpoint) al que pertenece (incidentes, exploits, zerodays, cves).
  2. 'data': El objeto con los campos específicos del esquema de ese módulo.

  ESQUEMAS:
  - incidentes: { fecha (YYYY-MM-DD), tipo (DataBreach, Ransomware, CyberAttack, Phishing, Defacement, Botnet, SupplyChain), entidad, pais, sector, descripcion, actor, url }
  - exploits: { fecha (YYYY-MM-DD), nombre, tipo (Network, Local, RemoteCodeExecution, PrivilegeEscalation, WebApplication, DoS, XSS), plataforma, cve, url }
  - zerodays: { idZD, fecha (YYYY-MM-DD), nombre, plataforma, cvss (number 0-10), estado (Activo, Mitigado, Investigacion, PruebaDeConcepto), url, descripcion }
  - cves: { cveId (CVE-YYYY-NNNN), fecha (YYYY-MM-DD), aplicativo, cvss (number 0-10), estado (Publicado, ExplotadoActivamente, Parcheado, Analisis, PruebaDeConcepto), descripcion, url }

  Usa la fecha de hoy si no encuentras una fecha de publicación clara.
  Responde SOLO con el objeto JSON válido.`;

  const response = await ai.models.generateContent({ 
    model: 'gemini-3-flash-preview', 
    contents: prompt,
    config: {
