export const addTicketComment = async (ticketId: string | number, comment: string): Promise<ApiResponse> => {
  const tickets = await fetchTickets();
  const ticket = tickets.find(t => String(t.id) === String(ticketId));
  if (!ticket) return { success: false, message: 'Ticket no encontrado' };
  const updatedTicket = {
    ...ticket,
    lastUpdated: Date.now(),
    activity: [...(ticket.activity || []), { type: 'comment' as const, timestamp: Date.now(), text: comment }]
  };
  return saveTicket(updatedTicket);
};

