const authenticateToken = (req, res, next) => {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];
    if (token == null) return res.status(401).json({ message: 'Token required.' });
    jwt.verify(token, JWT_SECRET, (err, user) => {
        if (err) return res.status(403).json({ message: 'Invalid token.' });
        req.user = user;
        next();
    });
};

protectedApiRouter.use(authenticateToken);

const createCrudRoutesFor = (modelName, model) => {
    const router = express.Router();
    router.get('/', async (req, res) => { try { const sortKey = model.schema.path('fecha') ? { fecha: -1 } : { createdAt: -1 }; const items = await model.find().sort(sortKey); res.status(200).json(items); } catch (err) { res.status(500).json({ message: `Error ${modelName}`, error: err.message }); } });
    router.post('/', async (req, res) => { try { const newItem = new model(req.body); const savedItem = await newItem.save(); res.status(201).json(savedItem); } catch (err) { res.status(400).json({ message: `Error create ${modelName}`, error: err.message }); } });
    router.put('/:id', async (req, res) => { try { const updatedItem = await model.findByIdAndUpdate(req.params.id, req.body, { new: true }); res.status(200).json(updatedItem); } catch (err) { res.status(400).json({ message: `Error update ${modelName}`, error: err.message }); } });
    router.delete('/:id', async (req, res) => { try { await model.findByIdAndDelete(req.params.id); res.status(204).send(); } catch (err) { res.status(500).json({ message: `Error delete ${modelName}`, error: err.message }); } });
    return router;
};

