            .trim()
            .substring(0, 25000); // Límite de seguridad para el prompt

        const apiKey = process.env.API_KEY;
        if (!apiKey) throw new Error("API_KEY not configured on server.");

        const ai = new GoogleGenAI({ apiKey });
        const prompt = `Actúa como un experto Analista de CTI. Analiza el contenido de esta noticia y clasifícala en: 'incidentes', 'exploits', 'zerodays' o 'cves'.

        CONTENIDO: ${cleanContent}
        URL: ${url}

        REGLAS DE SALIDA:
        Devuelve un JSON con:
        1. 'type': nombre del módulo (incidentes, exploits, zerodays, cves).
        2. 'data': objeto con campos del esquema.

        ESQUEMAS:
        - incidentes: { fecha (YYYY-MM-DD), tipo (DataBreach, Ransomware, CyberAttack, Phishing, Defacement, Botnet, SupplyChain), entidad, pais, sector, descripcion, actor, url }
        - exploits: { fecha (YYYY-MM-DD), nombre, tipo (Network, Local, RemoteCodeExecution, PrivilegeEscalation, WebApplication, DoS, XSS), plataforma, cve, url }
        - zerodays: { idZD, fecha (YYYY-MM-DD), nombre, plataforma, cvss (number), estado (Activo, Mitigado, Investigacion, PruebaDeConcepto), url, descripcion }
        - cves: { cveId (CVE-YYYY-NNNN), fecha (YYYY-MM-DD), aplicativo, cvss (number), estado (Publicado, ExplotadoActivamente, Parcheado, Analisis, PruebaDeConcepto), descripcion, url }

        Responde SOLO el JSON.`;

        const aiResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
