import { NewsItem, RiskTicket, RssFeedConfig } from '../types';

// Usamos una ruta relativa. 
// En desarrollo: Vite redirige /api -> localhost:3000 (gracias a vite.config.ts)
// En producción: El mismo server.js sirve el frontend y la API en el mismo puerto.
const API_BASE_URL = '/api';

// Module-scoped variable to hold the auth token
let authToken: string | null = localStorage.getItem('authToken');

export const setAuthToken = (token: string | null) => {
  authToken = token;
  if (token) {
    localStorage.setItem('authToken', token);
  } else {
    localStorage.removeItem('authToken');
  }
};

// Helper to get authorization headers
const getAuthHeaders = (): HeadersInit => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  if (authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }
  return headers;
};


// Helper to parse dates robustly
const parseDate = (dateString: string | null | undefined): Date | null => {
  if (!dateString) return null;
  let date = new Date(dateString);
  if (!isNaN(date.getTime())) {
    return date;
  }
  const cleanedString = dateString.replace(/(\sGMT|\s[A-Z]{3,4})$/, '').trim();
  date = new Date(cleanedString);
  if (!isNaN(date.getTime())) {
      return date;
  }
  return null;
};

const isWithinRange = (date: Date, start: Date, end: Date) => {
  return date >= start && date <= end;
};

// --- Generic Resource API ---

export interface ApiResponse {
  success: boolean;
  message?: string;
  data?: any;
}

const handleResponse = async (response: Response): Promise<ApiResponse> => {
  try {
    const contentType = response.headers.get('content-type');
    const isJson = contentType && contentType.includes('application/json');

    // Handle authentication errors globally
    if (response.status === 401 || response.status === 403) {
      setAuthToken(null); // Clear token on unauthorized/forbidden
      // Optionally, you might want to redirect to login or show a global message
      console.warn('Authentication failed or token expired. Logging out...');
      // For now, let the calling component handle navigation after this
    }

    if (isJson) {
      const data = await response.json();
      if (response.ok) {
        return { success: true, data: data.data || data, message: data.message };
      } else {
        return { success: false, message: data.message || `Error ${response.status}` };
      }
    } else {
      if (response.ok) {
         return { success: true, data: null };
      }
      const text = await response.text();
      const safeText = text.length > 100 ? text.substring(0, 100) + "..." : text;
      console.error(`Non-JSON API Error at ${response.url} [${response.status}]:`, safeText);

      if (response.status === 404) {
        return { success: false, message: `Recurso no encontrado (404). Verifica la URL del endpoint.` };
      }

      return { success: false, message: `Error de conexión con el Backend (Status ${response.status}). Asegúrate de ejecutar 'node server.js'.` };
    }
  } catch (error: any) {
    return { success: false, message: error.message || 'Error al procesar respuesta' };
  }
};

export const fetchResource = async <T>(endpoint: string): Promise<T[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}`, {
      headers: getAuthHeaders()
    });
    const result = await handleResponse(response);
    if (result.success) {
        return result.data as T[];
    }
    console.warn(`Failed to fetch ${endpoint}: ${result.message}`);
    return [];
  } catch (error) {
    console.warn(`Backend unavailable for ${endpoint}. Is server.js running on port 3000?`, error);
    return [];
  }
};

export const createResource = async <T>(endpoint: string, data: T): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}`, {
      method: 'POST',
      headers: getAuthHeaders(),
      body: JSON.stringify(data)
    });
    return handleResponse(response);
  } catch (error: any) {
    console.error(`Error creating resource ${endpoint}`, error);
    return { success: false, message: error.message || 'Error de conexión' };
  }
};

export const updateResource = async <T>(endpoint: string, id: string, data: T): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}/${id}`, {
      method: 'PUT',
      headers: getAuthHeaders(),
      body: JSON.stringify(data)
    });
    return handleResponse(response);
  } catch (error: any) {
    console.error(`Error updating resource ${endpoint}`, error);
    return { success: false, message: error.message || 'Error de conexión' };
  }
};

export const deleteResource = async (endpoint: string, id: string): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}/${id}`, {
      method: 'DELETE',
      headers: { ...getAuthHeaders(), 'Accept': 'application/json' }
    });
    if (response.status === 204) return { success: true };
    return handleResponse(response);
  } catch (error: any) {
    console.error(`Error deleting resource ${endpoint}`, error);
    return { success: false, message: error.message || 'Error de conexión' };
  }
};


// --- Digest API (RSS/Client Side) ---

// Management for Configurable Feeds
export const fetchRssFeeds = async (): Promise<RssFeedConfig[]> => {
    // RSS feeds can be public for now, or protected if backend is updated
    const response = await fetch(`${API_BASE_URL}/rss-feeds`, {
      headers: getAuthHeaders() // Even though it's unprotected by middleware, it still sends a token.
                                // This is fine, as the backend middleware for `/rss-feeds` doesn't check it.
    });
    const result = await handleResponse(response);
    if (result.success) {
        return result.data as RssFeedConfig[];
    }
    console.warn(`Failed to fetch rss-feeds: ${result.message}`);
    return [];
};

export const saveRssFeed = async (feed: RssFeedConfig): Promise<ApiResponse> => {
    return createResource('rss-feeds', feed);
};

export const deleteRssFeed = async (id: string): Promise<ApiResponse> => {
    return deleteResource('rss-feeds', id);
};


export const fetchDigest = async (days: number): Promise<NewsItem[]> => {
  try {
    // Now calls the backend directly, avoiding client-side CORS and parsing issues
    const data = await fetchResource<NewsItem>(`digest?days=${days}`);
    return data;
  } catch (err) {
    console.error("Error fetching digest:", err);
    return [];
  }
};

// --- Tickets/Risks API (Now using Real Database) ---

export const fetchTickets = async (): Promise<RiskTicket[]> => {
  return fetchResource<RiskTicket>('riesgos');
};

export const saveTicket = async (ticket: RiskTicket): Promise<void> => {
  if (ticket.id) {
    await updateResource('riesgos', String(ticket.id), ticket);
  } else {
    await createResource('riesgos', ticket);
  }
};

export const deleteTicket = async (id: string | number): Promise<void> => {
  await deleteResource('riesgos', String(id));
};

export const addTicketComment = async (ticketId: string | number, text: string): Promise<void> => {
  // Fetch current ticket to append comment (Simple approach without specialized sub-resource API)
  // A more advanced backend would have POST /api/riesgos/:id/comments
  const tickets = await fetchTickets();
  const ticket = tickets.find(t => t.id === ticketId);

  if (ticket) {
    const updatedTicket = {
      ...ticket,
      lastUpdated: Date.now(),
      activity: [
        ...ticket.activity,
        { type: 'comment' as const, timestamp: Date.now(), text }
      ]
    };
    await updateResource('riesgos', String(ticketId), updatedTicket);
  }
};

// --- Dashboard Statistics API ---

export interface DashboardStats {
  totalIncidents: number;
  totalExploits: number;
  totalZeroDays: number;
  totalCVEs: number;
  totalAlerts: number;
  ticketsByPriority: { name: string; value: number }[];
  ticketsByStatus: { name: string; value: number }[];
}

export const fetchDashboardStats = async (): Promise<DashboardStats> => {
  // Parallel fetch for efficiency
  const [tickets, incidents, exploits, zds, cves, alerts] = await Promise.all([
    fetchTickets(),
    fetchResource('incidentes'),
    fetchResource('exploits'),
    fetchResource('zerodays'), // Updated to zerodays
    fetchResource('cves'),
    fetchResource('alertas')
  ]);

  const priorityCount = tickets.reduce((acc, t) => {
    acc[t.priority] = (acc[t.priority] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const statusCount = tickets.reduce((acc, t) => {
    acc[t.status] = (acc[t.status] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  return {
    totalIncidents: (incidents as any[]).length,
    totalExploits: (exploits as any[]).length,
    totalZeroDays: (zds as any[]).length,
    totalCVEs: (cves as any[]).length,
    totalAlerts: (alerts as any[]).length,
    ticketsByPriority: [
      { name: 'Alta', value: priorityCount['high'] || 0 },
      { name: 'Media', value: priorityCount['medium'] || 0 },
      { name: 'Baja', value: priorityCount['low'] || 0 },
    ],
    ticketsByStatus: [
      { name: 'Detectado', value: statusCount['detectado'] || 0 },
      { name: 'Notificado', value: statusCount['notificado'] || 0 },
      { name: 'Mitigando', value: statusCount['mitigando'] || 0 },
      { name: 'Resuelto', value: statusCount['resuelto'] || 0 },
      { name: 'Aceptado', value: statusCount['riesgo-aceptado'] || 0 },
    ]
  };
};

// --- AI Analyst API ---

export const askAI = async (query: string): Promise<{ response: string }> => {
  try {
    const res = await fetch(`${API_BASE_URL}/ai/analyze`, {
      method: 'POST',
      headers: getAuthHeaders(),
      body: JSON.stringify({ query })
    });

    const result = await handleResponse(res);
    if (result.success) {
