riskSpecificRouter.put('/:id', async (req, res) => {
    try {
        const updateData = { ...req.body, lastUpdated: Date.now() };

        if (updateData.activity && Array.isArray(updateData.activity)) {
            const existingRisk = await Risk.findById(req.params.id);
            const existingActivityTimestamps = new Set(existingRisk?.activity.map(a => a.timestamp));

            updateData.activity = updateData.activity.map(log => {
                if (!existingActivityTimestamps.has(log.timestamp) || !log.username) {
                    return { ...log, username: req.user.username }; 
                }
                return log;
            });
        }

        const updatedRisk = await Risk.findByIdAndUpdate(req.params.id, updateData, { new: true, runValidators: true });
        if (!updatedRisk) return res.status(404).json({ message: "Riesgo no encontrado para actualizar" });
        res.status(200).json(updatedRisk);
    } catch (err) {
        res.status(400).json({ message: `Error al actualizar el riesgo`, error: err.message, details: err.errors });
    }
});
