apiRouter.post('/auth/register', async (req, res) => {
    try {
        const { username, password } = req.body;
        const passwordHash = await bcrypt.hash(password, 10);
        const newUser = new User({ username, passwordHash });
        await newUser.save();
        res.status(201).json({ message: 'User registered.' });
    } catch (err) { res.status(500).json({ message: 'Error registration.' }); }
});

apiRouter.post('/auth/login', async (req, res) => {
    try {
        const { username, password } = req.body;
        const user = await User.findOne({ username });
        if (!user || !await bcrypt.compare(password, user.passwordHash)) return res.status(401).json({ message: 'Invalid credentials.' });
        const token = jwt.sign({ userId: user._id, username: user.username }, JWT_SECRET, { expiresIn: JWT_EXPIRATION_TIME });
        res.status(200).json({ token, username: user.username });
    } catch (err) { res.status(500).json({ message: 'Error login.' }); }
});

// --- AI TRIAJE CON SCRAPING CHEERIO MEJORADO ---
protectedApiRouter.post('/ai/triage', async (req, res) => {
    try {
        const { url } = req.body;
        if (!url) return res.status(400).json({ message: "URL is required" });

        const { data: html } = await axios.get(url, { 
            timeout: 15000, 
            headers: { 'User-Agent': 'Mozilla/5.0 (compatible; OSINT-Brief-Bot/2.0)' } 
        });

        const $ = cheerio.load(html);

        const title = $("h1").first().text().trim();
        const author = $("[class*='author']").first().text().trim();
        const date = $("time").attr("datetime") || $("time").text().trim() || new Date().toISOString().split('T')[0];

        const paragraphs = [];
        const contentSelector = $("article p").length > 0 ? "article p" : "main p, body p";
        $(contentSelector).each((i, el) => {
            const text = $(el).text().trim();
            if (text.length > 40) paragraphs.push(text);
        });

        const cleanContent = paragraphs.join("\n\n").substring(0, 15000);

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Actúa como Analista CTI senior. Clasifica estos datos en 'incidentes', 'exploits', 'zerodays' o 'cves'.

        URL: ${url}
        TÍTULO: ${title}
        AUTOR: ${author}
        FECHA: ${date}
        CONTENIDO: ${cleanContent}

        Responde SOLO un JSON: { "type": "modulo", "data": { ...campos_segun_esquema... } }`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: "application/json" }
        });

        res.json(JSON.parse(response.text));
    } catch (err) {
        res.status(500).json({ message: "Error en triaje", error: err.message });
    }
});

